#!/usr/bin/env bash
# Quick summary of a JTL file: throughput, latency percentiles, error rate.
# JMeter's HTML report (auto-generated by run.sh) has the full breakdown — this
# is for "did the run succeed?" at a glance from a terminal.
#
#   scripts/analyze-results.sh results/results-20260617-120000.jtl

set -euo pipefail

JTL="${1:-}"
if [[ -z "$JTL" || ! -f "$JTL" ]]; then
    echo "Usage: $0 <path-to-results.jtl>" >&2
    exit 1
fi

python3 - "$JTL" <<'PY'
import csv, statistics, sys
path = sys.argv[1]
elapsed, successes, errors, start_min, start_max = [], 0, 0, None, None
with open(path, newline="") as f:
    r = csv.DictReader(f)
    for row in r:
        try:
            ms = int(row["elapsed"])
            ts = int(row["timeStamp"])
        except (KeyError, ValueError):
            continue
        elapsed.append(ms)
        if row.get("success", "").lower() == "true":
            successes += 1
        else:
            errors += 1
        start_min = ts if start_min is None else min(start_min, ts)
        start_max = ts if start_max is None else max(start_max, ts)

n = len(elapsed)
if n == 0:
    print("No samples found.")
    sys.exit(0)

elapsed.sort()
def pct(p): return elapsed[min(int(p / 100 * n), n - 1)]
duration_s = max((start_max - start_min) / 1000.0, 0.001)

print(f"Samples:    {n:>12,}")
print(f"Successes:  {successes:>12,}")
print(f"Errors:     {errors:>12,}    ({errors / n * 100:.2f}%)")
print(f"Duration:   {duration_s:>12.1f} s")
print(f"Throughput: {n / duration_s:>12.1f} req/s")
print(f"Latency ms:")
print(f"  avg  {statistics.mean(elapsed):>10.1f}")
print(f"  p50  {pct(50):>10}")
print(f"  p90  {pct(90):>10}")
print(f"  p95  {pct(95):>10}")
print(f"  p99  {pct(99):>10}")
print(f"  max  {elapsed[-1]:>10}")
PY
